Code.Terraform:
```hcl
# 在 OpenSearch 域上启用细粒度访问控制（FGAC）
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  advanced_security_options {
    enabled = true  # 关键：开启 FGAC
    master_user_options {
      master_user_arn = "<MASTER_USER_ARN>"  # 关键：需要使用 IAM 主体启用 FGAC
    }
  }
}
```
